VALUES
  ('judicial-de09bf8b-moex-00139', 'judicial-de09bf8b', 'judicial-de09bf8b-moex-112-e2754278', 'sub-judicial-de09bf8b-01', NULL, 'single_choice', '解送依法拘禁之人犯甲時，負責看管人犯之員警乙，不小心讓甲脫逃。甲、乙之行為，下列敘述 何者正確？', '["甲、乙均不成立犯罪", "甲成立脫逃罪；乙不成立犯罪", "甲不成立犯罪；乙成立過失致脫逃罪", "甲成立脫逃罪；乙成立過失致脫逃罪"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:19+00:00", "source_pdf_sha1": "d730c10a9f02", "answer_pdf_sha1": "011096dce3ab", "source_family": "moex-gov-tw", "moex": {"exam_code": "112130", "c": "201", "s": "0504", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "刑法概要", "year": "112", "exam_name": "112年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 13, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "法院書記官"}'::jsonb, NULL),
  ('judicial-de09bf8b-moex-00140', 'judicial-de09bf8b', 'judicial-de09bf8b-moex-112-e2754278', 'sub-judicial-de09bf8b-01', NULL, 'single_choice', '甲到警察局報案，表示其剛才所領的薪水被飛車搶奪，警察調閱街頭錄影帶發現並無此事，甲才 承認因為賭博將錢花光，對太太無法交代，才出此下策，警察應如何處理甲之行為？', '["應偵辦甲刑法第169條的誣告他人罪", "不應偵辦甲行為，因為其未誣告他人", "應偵辦甲刑法第171條未指定犯人誣告罪", "不應偵辦甲行為，因其行為情有可原"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:19+00:00", "source_pdf_sha1": "d730c10a9f02", "answer_pdf_sha1": "011096dce3ab", "source_family": "moex-gov-tw", "moex": {"exam_code": "112130", "c": "201", "s": "0504", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "刑法概要", "year": "112", "exam_name": "112年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 14, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "法院書記官"}'::jsonb, NULL),
  ('judicial-de09bf8b-moex-00141', 'judicial-de09bf8b', 'judicial-de09bf8b-moex-112-e2754278', 'sub-judicial-de09bf8b-01', NULL, 'single_choice', '有關刑法第185條之4肇事逃逸罪，下列敘述何者正確？', '["甲駕駛汽車失控，撞擊路邊停放之乙車，導致乙車車門凹陷，甲立即逃逸，甲成立本罪", "甲與乙均騎自行車，在車道上相撞，乙受傷而甲逃逸，甲成立本罪", "甲駕駛汽車失控，撞擊乙車，導致乙受輕傷，甲立即逃逸，甲不成立本罪", "甲駕駛汽車失控而撞上前方之機車，機車騎士乙當場死亡，甲立即逃逸，甲成立本罪"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:19+00:00", "source_pdf_sha1": "d730c10a9f02", "answer_pdf_sha1": "011096dce3ab", "source_family": "moex-gov-tw", "moex": {"exam_code": "112130", "c": "201", "s": "0504", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "刑法概要", "year": "112", "exam_name": "112年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 15, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "法院書記官"}'::jsonb, NULL),
  ('judicial-de09bf8b-moex-00142', 'judicial-de09bf8b', 'judicial-de09bf8b-moex-112-e2754278', 'sub-judicial-de09bf8b-01', NULL, 'single_choice', '有關刑法第15章偽造文書印文罪，下列敘述何者錯誤？', '["偽造私文書或偽造公文書罪都必須足生損害於他人或公眾", "變造汽車牌照號碼是成立刑法第212條變造特種文書罪", "偽造臺灣臺北地方法院的印文成立刑法第217條僞造公印文罪", "互助會標單不是刑法第220條所稱之準文書"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:19+00:00", "source_pdf_sha1": "d730c10a9f02", "answer_pdf_sha1": "011096dce3ab", "source_family": "moex-gov-tw", "moex": {"exam_code": "112130", "c": "201", "s": "0504", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "刑法概要", "year": "112", "exam_name": "112年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 16, "answer_corrected": true, "flags": ["answer_corrected_skip_v1"], "civil_slug": "judicial", "civil_category": "法院書記官"}'::jsonb, NULL),
  ('judicial-de09bf8b-moex-00143', 'judicial-de09bf8b', 'judicial-de09bf8b-moex-112-e2754278', 'sub-judicial-de09bf8b-01', NULL, 'single_choice', '有關刑法第16章之1妨害風化罪，下列敘述何者錯誤？', '["公然猥褻罪主觀上必須有意圖供人觀覽始成立犯罪", "與四親等之表妹發生性交，成立刑法第230條血親性交罪", "散布人獸交圖片，成立散布猥褻圖畫罪", "公務員犯包庇他人犯意圖使女子與他人為性交之行為，而媒介以營利罪，加重其刑至二分之一"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:19+00:00", "source_pdf_sha1": "d730c10a9f02", "answer_pdf_sha1": "011096dce3ab", "source_family": "moex-gov-tw", "moex": {"exam_code": "112130", "c": "201", "s": "0504", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "刑法概要", "year": "112", "exam_name": "112年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 17, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "法院書記官"}'::jsonb, NULL),
  ('judicial-de09bf8b-moex-00144', 'judicial-de09bf8b', 'judicial-de09bf8b-moex-112-e2754278', 'sub-judicial-de09bf8b-01', NULL, 'single_choice', '政府三申五令禁止公務員涉足有女陪侍的酒店，在這些風化場所進行性交或猥褻的違法性交易行 為，所引發的刑法問題，下列敘述何者正確？', '["在封閉式包廂內陪侍之女性，可能觸犯刑法第234條公然猥褻罪", "陪侍女性主動引致性交易者，可能觸犯刑法第231條引誘營利罪", "開設酒店之人媒介性交易者，可能觸犯刑法第231條媒介營利罪", "公務員前往消費行為本身，即構成刑法第231條第2項包庇行為"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:19+00:00", "source_pdf_sha1": "d730c10a9f02", "answer_pdf_sha1": "011096dce3ab", "source_family": "moex-gov-tw", "moex": {"exam_code": "112130", "c": "201", "s": "0504", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "刑法概要", "year": "112", "exam_name": "112年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 18, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "法院書記官"}'::jsonb, NULL),
  ('judicial-de09bf8b-moex-00145', 'judicial-de09bf8b', 'judicial-de09bf8b-moex-112-e2754278', 'sub-judicial-de09bf8b-01', NULL, 'single_choice', '甲因對其祖父乙索取金錢遭拒，憤而持花瓶丟向祖父乙，卻未丟中，有關甲之刑責為何？', '["傷害未遂罪", "義憤傷害未遂罪", "施強暴於直系血親尊親屬罪", "不成立犯罪"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:19+00:00", "source_pdf_sha1": "d730c10a9f02", "answer_pdf_sha1": "011096dce3ab", "source_family": "moex-gov-tw", "moex": {"exam_code": "112130", "c": "201", "s": "0504", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "刑法概要", "year": "112", "exam_name": "112年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 19, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "法院書記官"}'::jsonb, NULL),
  ('judicial-de09bf8b-moex-00146', 'judicial-de09bf8b', 'judicial-de09bf8b-moex-112-e2754278', 'sub-judicial-de09bf8b-01', NULL, 'single_choice', '有關刑法第283條聚眾鬥毆罪的敘述，下列何者錯誤？', '["本罪罪質屬抽象危險犯", "致人於死或重傷，係屬客觀處罰條件", "本罪屬對向犯", "在場助勢者為本罪之行為人"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:19+00:00", "source_pdf_sha1": "d730c10a9f02", "answer_pdf_sha1": "011096dce3ab", "source_family": "moex-gov-tw", "moex": {"exam_code": "112130", "c": "201", "s": "0504", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "刑法概要", "year": "112", "exam_name": "112年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 20, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "法院書記官"}'::jsonb, NULL),
  ('judicial-de09bf8b-moex-00147', 'judicial-de09bf8b', 'judicial-de09bf8b-moex-112-e2754278', 'sub-judicial-de09bf8b-01', NULL, 'single_choice', '甲向學校老師威脅如果不給高分，就向學校誣告遭老師性騷擾，老師擔心無端受牽連只好給高分。 甲在刑法上成立何罪：', '["強制罪", "誹謗罪", "強制猥褻罪", "誣告罪"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:19+00:00", "source_pdf_sha1": "d730c10a9f02", "answer_pdf_sha1": "011096dce3ab", "source_family": "moex-gov-tw", "moex": {"exam_code": "112130", "c": "201", "s": "0504", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "刑法概要", "year": "112", "exam_name": "112年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 21, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "法院書記官"}'::jsonb, NULL),
  ('judicial-de09bf8b-moex-00148', 'judicial-de09bf8b', 'judicial-de09bf8b-moex-112-e2754278', 'sub-judicial-de09bf8b-01', NULL, 'single_choice', '有關刑法第28章妨害秘密罪，下列敘述何者錯誤？', '["甲為知悉心儀已久之乙女所收到之信件內容，將信封置於燈下照射因而得知其內容，甲成立妨 害書信秘密罪", "里長甲因乙住家附近竊盜案件增加，故在人行道裝設監視器，因而錄得乙與男友在人行道接吻， 甲成立窺視竊聽竊錄罪", "甲在更衣室以遠端遙控隱藏鏡頭方式，錄影其他人更衣之情形，甲成立窺視竊聽竊錄罪", "甲將更衣室所竊錄的內容以網路傳送方式供不特定人下載，甲成立散布竊錄他人活動罪"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:19+00:00", "source_pdf_sha1": "d730c10a9f02", "answer_pdf_sha1": "011096dce3ab", "source_family": "moex-gov-tw", "moex": {"exam_code": "112130", "c": "201", "s": "0504", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "刑法概要", "year": "112", "exam_name": "112年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 22, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "法院書記官"}'::jsonb, NULL)
